const fs = require('fs');
const crypto = require('crypto');
const path = '/files/dedupe_store.json';

// Initialize store safely
let store = {};
try {
  if (fs.existsSync(path)) {
    store = JSON.parse(fs.readFileSync(path, 'utf8'));
  } else {
    fs.writeFileSync(path, JSON.stringify({}), 'utf8');
  }
} catch(e) {
  console.error('Dedupe file error:', e.message);
  // Fallback to empty store if file access fails
  store = { urls: {}, titles: {}, hashes: {} };
}

const now = new Date().toISOString();
const newItems = [];
const sevenDays = 7 * 24 * 60 * 60 * 1000;

function isOlderThan7Days(ts) {
  try {
    return (Date.now() - new Date(ts).getTime()) > sevenDays;
  } catch {
    return false; // treat invalid dates as fresh
  }
}

// Default all items as fresh if error occurs
if (!items || !Array.isArray(items)) {
  console.warn('No items array or malformed:', items);
  return newItems; // Continue upstream items
}

for (const item of items) {
  try {
    if (!item.url || !item.title) {
      console.warn('Item missing url or title:', item);
      continue;
    }

    // Normalize title for comparison
    const normTitle = (item.title || '').toLowerCase()
      .replace(/[^a-z0-9\s]/g, '')
      .replace(/\s+/g, ' ')
      .trim();

    // Check duplicates with error safety
    if (store.urls[item.url] && !isOlderThan7Days(store.urls[item.url])) {
      item.skip_reason = 'DUPLICATE_URL';
      continue;
    }
    if (store.titles[normTitle] && !isOlderThan7Days(store.titles[normTitle])) {
      item.skip_reason = 'DUPLICATE_TITLE';
      continue;
    }

    // Hash first 500 chars for content comparison
    let contentHash = '';
    try {
      contentHash = crypto.createHash('sha1')
        .update((item.raw_content || item.content || '').substring(0, 500))
        .digest('hex');
    } catch (e) {
      contentHash = crypto.createHash('sha1')
        .update(item.url)
        .digest('hex');
    }

    // Check duplicate hashes
    if (store.hashes[contentHash] && !isOlderThan7Days(store.hashes[contentHash])) {
      item.skip_reason = 'DUPLICATE_CONTENT';
      continue;
    }

    // Process non-duplicate item
    newItems.push(item);
    store.urls[item.url] = now;
    store.titles[normTitle] = now;
    store.hashes[contentHash] = now;

  } catch (err) {
    console.error('Item processing error:', err.message);
    // Keep any item failures isolated
    continue;
  }
}

// Prune old entries
function safePrune(obj) {
  for (const key in obj) {
    try {
      if (isOlderThan7Days(obj[key])) {
        delete obj[key];
      }
    } catch (e) {
      console.error('Prune error:', e.message);
    }
  }
}

safePrune(store.urls);
safePrune(store.titles);
safePrune(store.hashes);

// Write store with error handling
try {
  fs.writeFileSync(path, JSON.stringify(store, null, 2), 'utf8');
} catch (e) {
  console.error('Store file write error:', e.message);
  // Graceful degradation - proceed without saving state
}

// Return new items with debug info
return newItems.map(item => ({
  ...item,
  dedupe_debug: {
    url: item.url,
    skip: item.skip_reason || null
  }
}));
```

